class Solution:
    def friendRequests(self, n, restrictions, requests):
        adj = [set() for _ in range(n)]
        def component(start):
            seen = {start}
            stack = [start]
            while stack:
                cur = stack.pop()
                for nxt in adj[cur]:
                    if nxt not in seen:
                        seen.add(nxt)
                        stack.append(nxt)
            return seen
        result = []
        for u, v in requests:
            comp_u = component(u)
            if v in comp_u:
                result.append(True)
                continue
            comp_v = component(v)
            blocked = False
            for x, y in restrictions:
                if (x in comp_u and y in comp_v) or (x in comp_v and y in comp_u):
                    blocked = True
                    break
            if blocked:
                result.append(False)
            else:
                adj[u].add(v)
                adj[v].add(u)
                result.append(True)
        return result

