class Solution:
    def friendRequests(self, n, restrictions, requests):
        parent = list(range(n))
        rank = [0] * n
        def find(x):
            root = x
            while parent[root] != root:
                root = parent[root]
            while parent[x] != root:
                parent[x], x = root, parent[x]
            return root
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra == rb:
                return
            if rank[ra] < rank[rb]:
                ra, rb = rb, ra
            parent[rb] = ra
            if rank[ra] == rank[rb]:
                rank[ra] += 1
        result = []
        for u, v in requests:
            ru, rv = find(u), find(v)
            if ru == rv:
                result.append(True)
                continue
            blocked = False
            for x, y in restrictions:
                rx, ry = find(x), find(y)
                if (rx == ru and ry == rv) or (rx == rv and ry == ru):
                    blocked = True
                    break
            if blocked:
                result.append(False)
            else:
                union(u, v)
                result.append(True)
        return result

